example.code:
#!/bin/bash # Create-or-attach pattern (safe to call repeatedly) SESSION="${1:-dev}" DIR="${2:-$(pwd)}"
if tmux has-session -t "$SESSION" 2>/dev/null; then tmux attach -t "$SESSION" exit 0 fi
# Create new session with layout tmux new-session -d -s "$SESSION" -c "$DIR" tmux rename-window -t "$SESSION:1" "edit" tmux new-window -t "$SESSION" -n "term" -c "$DIR" tmux new-window -t "$SESSION" -n "run" -c "$DIR" tmux split-window -h -t "$SESSION:run" -c "$DIR" tmux select-window -t "$SESSION:1" tmux attach -t "$SESSION"
